# .github/workflows/genai-branch-eval.yml equivalent, implemented in Python
# Run this in CI before any merge to trunk.

import subprocess, sys, json, pathlib

EVAL_SCRIPT = "scripts/run_evals.py"
PASS_RATE_THRESHOLD = 0.90   # 90% of test cases must pass
REGRESSION_TOLERANCE = 0.02  # allow ≤2pp drop vs baseline

def run_eval(branch_name: str) -> dict:
    result = subprocess.run(
        ["python", EVAL_SCRIPT, "--output-json"],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        print(result.stderr)
        sys.exit(1)
    return json.loads(result.stdout)

def load_baseline() -> dict:
    p = pathlib.Path("eval_baselines/main.json")
    if not p.exists():
        return {}
    return json.loads(p.read_text())

def check_merge_gate(branch_name: str) -> None:
    current = run_eval(branch_name)
    baseline = load_baseline()

    pass_rate = current["pass_rate"]
    if pass_rate < PASS_RATE_THRESHOLD:
        print(f"FAIL: pass rate {pass_rate:.2%} < threshold {PASS_RATE_THRESHOLD:.2%}")
        sys.exit(1)

    if baseline:
        delta = pass_rate - baseline.get("pass_rate", pass_rate)
        if delta < -REGRESSION_TOLERANCE:
            print(f"FAIL: regression {delta:.2%} exceeds tolerance -{REGRESSION_TOLERANCE:.2%}")
            sys.exit(1)

    print(f"PASS: pass_rate={pass_rate:.2%}, delta={delta:+.2%}")

if __name__ == "__main__":
    branch = sys.argv[1] if len(sys.argv) > 1 else "unknown"
    check_merge_gate(branch)

# Day 0 (afternoon): create branch from trunk
git checkout main && git pull
git checkout -b tool-schema/add-web-search-tool

# Add the tool definition
cat > src/tools/web_search.json << 'EOF'
{
  "name": "web_search",
  "description": "Search the web for current information. Use only when the user asks about events after your knowledge cutoff or requests live data.",
  "parameters": {
    "type": "object",
    "properties": {
      "query": {
        "type": "string",
        "description": "A concise search query, max 120 characters"
      },
      "max_results": {
        "type": "integer",
        "description": "Number of results to return (1-5)",
        "default": 3
      }
    },
    "required": ["query"]
  }
}
EOF

# Update system prompt to reference the new tool
# (edit src/prompts/system.txt — one focused addition)
echo "\n\nUse the web_search tool when the user asks about current events or live data." >> src/prompts/system.txt

# Run the eval suite
python scripts/run_evals.py --suite search
